13→export const DEEP_RESEARCH_NODE = DEEP_RESEARCH_DISPATCH_TARGET;
14→
15→const COORDINATOR_SYSTEM_PROMPT = `你是「AI 助手」，一位友好且专业的助手。
16→
17→# 职责
18→
19→- 响应问候语（如"你好"、"早上好"）和日常闲聊
20→- 礼貌拒绝不当或有害请求
21→- 需要深入研究、信息检索、复杂规划、结构化报告时，将任务派发给 deep-research
22→
23→# 可用动作
24→
25→- 当需要更多信息时，调用 ask-user 工具
26→- 当需要深入研究时，调用 dispatch 工具，并将 name 设置为 deep-research
27→- 当你已经准备好直接回复用户时，直接输出最终答案
28→
29→# 注意事项
30→
31→- 始终使用和用户相同的语言
32→- 尽可能减少 ask-user 的使用次数；如果必须提问，应一次性把当前缺失的关键信息都问完
33→- 只要你是在向用户索取缺失信息、澄清范围、确认地点/时间/对象，必须调用 ask-user 工具，绝对不要直接输出文字问题
34→- 任何带有“请问/请提供/请告诉我/你想看哪个城市/还需要补充什么”等澄清性质的话，都必须通过 ask-user 发出，不能作为普通 assistant 文本输出
35→- 如果信息不足以继续执行 deep-research，你唯一允许的动作是 ask-user；禁止先输出一段问题再结束
36→- 只有在你已经拿到足够信息、且不需要用户再补充任何内容时，才能直接输出最终答案
37→- 调用 ask-user 后，停止后续输出，等待用户回复
38→- 调用 dispatch 后，停止后续输出，由 deep-research 接管`;
39→
40→export const createCoordinatorNode = (llm: LanguageModelLike) => {
41→  const agent = createAgent({
42→    model: llm,
43→    tools: [askUserTool, dispatchTool],
44→    middleware: [createToolErrorMiddleware(), dynamicSystemPromptMiddleware(async () => COORDINATOR_SYSTEM_PROMPT)],
45→  });
46→
47→  return async (state: State): Promise<Command> => {
48→    const response = await agent.invoke({ messages: state.messages });
49→    const additional = response.messages.slice(state.messages.length);
50→    const update: SetRequired<Partial<State>, 'messages'> = { messages: additional };
51→
52→    const askUser = getToolCallResultMessage(additional, EToolName.AskUser);
53→    if (askUser?.artifact) {
54→      update.pendingInteraction = {
55→        ...(askUser.artifact as IAskUserPayload),
56→        agent: ENodeName.Coordinator,
57→        resumeNode: ENodeName.Coordinator,
58→      };
59→      return new Command({ goto: ENodeName.Interaction, update });
60→    }
61→
62→    const dispatch = getToolCallResultMessage(additional, EToolName.Dispatch);
63→    if (dispatch?.artifact) {
64→      const target = (dispatch.artifact as { name?: unknown }).name;
65→      if (target !== DEEP_RESEARCH_NODE) {
66→        throw new Error('Unknown dispatch target');
67→      }
68→      return new Command({ goto: DEEP_RESEARCH_NODE, update });
69→    }
70→
71→    return new Command({ goto: END, update });
72→  };
73→};
